        "image": "/guided-reading/pages/tale-of-peter-rabbit/page-001.webp",
        "text": "THE TALE OF\n\nPETER RABBIT\n\nBY\n\nBEATRIX POTTER\n\nFREDERICK WARNE",
        "imageAlt": "The Tale of Peter Rabbit page 1",
        "pageDescription": "The Tale of Peter Rabbit page 1",
        "embeddedImageText": "",
